import{_ as l,c as i,o,ag as s}from"./chunks/framework.D4Vqf8I7.js";const P=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/pve/resources.md","filePath":"docs/wi/pve/resources.md","lastUpdated":1784647058000}'),t={name:"docs/wi/pve/resources.md"};function r(p,e,a,c,_,n){return o(),i("div",null,e[0]||(e[0]=[s("<p>Отдельного глобального параметра «коэффициент переподписки CPU/RAM», который можно изменить одной настройкой для всего гипервизора нет. Коэффициент переподписки формируется фактически, через суммарное количество ресурсов, назначенных виртуальным машинам.</p><p>Для CPU - Коэффициент CPU-переподписки = сумма vCPU всех ВМ / количество физических CPU-ядер/потоков узла</p><p>Если на узле доступно 32 логических CPU, а всем ВМ суммарно выделено 64 vCPU, коэффициент переподписки будет 1:2. Изменяется он не отдельной настройкой гипервизора, а через параметры конкретных ВМ:</p><ul><li>количество sockets/cores/vCPU у ВМ;</li><li>лимиты CPU, если они используются;</li><li>распределение ВМ по узлам кластера.</li></ul><p>Для RAM аналогично - Коэффициент переподписки памяти = сумма назначенной ВМ памяти / физический объём RAM узла Изменяется он через параметры памяти конкретных ВМ:</p><ul><li>объём Memory;</li><li>Ballooning, если используется;</li><li>лимиты/резервирование памяти;</li><li>распределение ВМ по узлам.</li></ul><p>То есть практическая инструкция по изменению коэффициента такая:</p><ol><li>Посчитать физические ресурсы узла: количество CPU и объём RAM.</li><li>Посчитать суммарно выделенные ВМ vCPU и RAM.</li><li>При необходимости изменить параметры ВМ, уменьшить/увеличить vCPU и RAM.</li><li>Перераспределить ВМ между узлами кластера, если требуется снизить нагрузку на конкретный узел.</li><li>Оставить резерв ресурсов для самого гипервизора и системных сервисов.</li></ol><p>Не рекомендуется стремиться к 100% использованию всех ресурсов хоста виртуальными машинами, особенно по памяти. Для стабильной работы необходимо оставлять запас под сам гипервизор, службы хранения, сеть, процессы QEMU/KVM и возможные пики нагрузки.</p>",9)]))}const C=l(t,[["render",r]]);export{P as __pageData,C as default};
